// capture-processor.js  — registered as an AudioWorklet module
// Converts Float32 microphone samples to Int16 PCM and posts them
// to the main thread. The main thread accumulates frames and
// forwards them over a WebSocket.

class CaptureProcessor extends AudioWorkletProcessor {
  constructor() {
    super();
    this._buffer = [];
    this._frameSize = 320; // 20 ms at 16 kHz
  }

  process(inputs) {
    const input = inputs[0];
    if (!input || !input[0]) return true;

    const float32 = input[0]; // 128 Float32 samples per call

    // Convert Float32 → Int16
    for (let i = 0; i < float32.length; i++) {
      // Clamp to [-1, 1], then scale to Int16 range
      const clamped = Math.max(-1, Math.min(1, float32[i]));
      this._buffer.push(Math.round(clamped * 32767));
    }

    // Emit complete 20 ms frames
    while (this._buffer.length >= this._frameSize) {
      const frame = this._buffer.splice(0, this._frameSize);
      const int16 = new Int16Array(frame);
      // Transfer ownership — zero-copy
      this.port.postMessage({ type: 'pcm', data: int16 }, [int16.buffer]);
    }

    return true; // keep processor alive
  }
}

registerProcessor('capture-processor', CaptureProcessor);

// --- main thread setup ---
async function startCapture(ws) {
  const stream = await navigator.mediaDevices.getUserMedia({
    audio: {
      sampleRate: 16000,
      channelCount: 1,
      echoCancellation: true,
      noiseSuppression: true,
      autoGainControl: true,
    }
  });

  const audioCtx = new AudioContext({ sampleRate: 16000 });
  await audioCtx.audioWorklet.addModule('/capture-processor.js');

  const source = audioCtx.createMediaStreamSource(stream);
  const worklet = new AudioWorkletNode(audioCtx, 'capture-processor');

  worklet.port.onmessage = (event) => {
    if (event.data.type !== 'pcm') return;
    // Backpressure gate: don't flood the WebSocket
    if (ws.bufferedAmount > 8192) return;
    ws.send(event.data.data.buffer);
  };

  source.connect(worklet);
  // worklet is not connected to destination — we only want to read, not output
  return audioCtx;
}

// playback.js — schedule incoming PCM16 chunks for gapless playback

class AudioPlaybackScheduler {
  constructor(sampleRate = 16000) {
    this.audioCtx = new AudioContext({ sampleRate });
    this.nextPlayTime = 0;     // AudioContext time of the next chunk's start
    this.sampleRate = sampleRate;
  }

  /**
   * Decode a raw Int16 ArrayBuffer and schedule it for playback.
   * Calling this in sequence (without awaiting) produces seamless audio
   * regardless of when the WebSocket message actually arrived.
   */
  scheduleChunk(int16Buffer) {
    // Resume context if browser suspended it (tab backgrounded, etc.)
    if (this.audioCtx.state === 'suspended') {
      this.audioCtx.resume();
    }

    const int16 = new Int16Array(int16Buffer);
    const numSamples = int16.length;

    // Create AudioBuffer for this chunk
    const audioBuffer = this.audioCtx.createBuffer(
      1,           // mono
      numSamples,
      this.sampleRate
    );

    // Decode Int16 PCM → Float32 in-place
    const float32 = audioBuffer.getChannelData(0);
    for (let i = 0; i < numSamples; i++) {
      float32[i] = int16[i] / 32768.0; // normalise to [-1, 1]
    }

    const source = this.audioCtx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.audioCtx.destination);

    // Schedule at the end of the previous chunk, or "now" if we've fallen behind
    const startAt = Math.max(this.nextPlayTime, this.audioCtx.currentTime + 0.01);
    source.start(startAt);

    // Advance the cursor by the duration of this chunk
    this.nextPlayTime = startAt + audioBuffer.duration;
  }

  /** Clear the playback queue (e.g., when barge-in interrupts the agent). */
  flush() {
    this.nextPlayTime = 0;
    // Re-create AudioContext to stop all scheduled nodes immediately
    this.audioCtx.close();
    this.audioCtx = new AudioContext({ sampleRate: this.sampleRate });
  }
}

// Usage with WebSocket
const scheduler = new AudioPlaybackScheduler(16000);
const ws = new WebSocket('wss://your-voice-agent/ws');

ws.binaryType = 'arraybuffer';
ws.onmessage = (event) => {
  if (event.data instanceof ArrayBuffer) {
    scheduler.scheduleChunk(event.data);
  }
};
